SELECT
    COALESCE(SUM(
        CASE WHEN c.type = 'income' THEN e.credit ELSE 0 END
    ), 0) AS totalIncome,
    COALESCE(SUM(
        CASE WHEN c.type = 'expense' THEN e.debit ELSE 0 END
    ), 0) AS totalExpense,
    COUNT(DISTINCT CASE WHEN c.type = 'income' THEN t.id END) AS incomeCount,
    COUNT(DISTINCT CASE WHEN c.type = 'expense' THEN t.id END) AS expenseCount
FROM transactions t
INNER JOIN entries e ON e.transaction_id = t.id AND e.account_type = 'category'
INNER JOIN categories c ON c.id = e.account_id
WHERE t.user_id = #{userId}
  AND t.is_deleted = 0
  AND t.date >= #{startDate}
  AND t.date <= #{endDate}

SELECT COALESCE(SUM(e.debit), 0) AS total_expense
FROM transactions t
INNER JOIN entries e ON e.transaction_id = t.id AND e.account_type = 'category' AND e.account_id = #{categoryId}
WHERE t.user_id = #{userId}
  AND t.is_deleted = 0
  AND t.date >= #{startDate}
  AND t.date <= #{endDate}

SELECT COALESCE(SUM(e.debit), 0) AS total_expense
FROM transactions t
INNER JOIN entries e ON e.transaction_id = t.id AND e.account_type = 'category'
INNER JOIN categories c ON c.id = e.account_id
WHERE t.user_id = #{userId}
  AND t.is_deleted = 0
  AND c.type = 'expense'
  AND t.date >= #{startDate}
  AND t.date <= #{endDate}
